var input = $input.first().json;
var candidates   = input.candidates   || [];
var interviewers = input.interviewers || [];
var rooms        = input.rooms        || [];
var superDayDate = input.superDayDate || new Date().toISOString().split('T')[0];
var DURATION = 45;
var ROUNDS = [
  { name: 'Technical/Domain', startTime: '10:00' },
  { name: 'Cross-Functional', startTime: '11:45' },
  { name: 'Culture Fit',      startTime: '13:30' }
];
function toMins(t) { var p=t.split(':').map(Number); return p[0]*60+p[1]; }
function fromMins(m) { return String(Math.floor(m/60)).padStart(2,'0')+':'+String(m%60).padStart(2,'0'); }
function addMins(t,m) { return fromMins(toMins(t)+m); }
function conflictsWithBlocks(s,e,blocks) {
  for (var i=0;i<(blocks||[]).length;i++) { if (toMins(s)<toMins(blocks[i].end)&&toMins(e)>toMins(blocks[i].start)) return true; }
  return false;
}
function exceedsHardStop(e,h) { return h && toMins(e)>toMins(h); }
var usedIv={}; var usedRoom={};
function findIv(candidate,round,allIv) {
  var s=round.startTime; var e=addMins(s,DURATION);
  if (!usedIv[s]) usedIv[s]={};
  var senRank=['VP','Chief','Director','Lead','Senior','Manager','Architect','Partner'];
  var eligible=allIv.filter(function(iv){
    if (usedIv[s][iv.id]) return false;
    if (iv.availableFrom&&toMins(s)<toMins(iv.availableFrom)) return false;
    if (iv.availableTill&&toMins(e)>toMins(iv.availableTill)) return false;
    return true;
  }).sort(function(a,b){
    var dept=candidate.role||'';
    if (round.name==='Technical/Domain') {
      return ((a.department||'').toLowerCase()===dept.toLowerCase()?0:1)-((b.department||'').toLowerCase()===dept.toLowerCase()?0:1);
    } else if (round.name==='Cross-Functional') {
      return ((a.department||'').toLowerCase()!==dept.toLowerCase()?0:1)-((b.department||'').toLowerCase()!==dept.toLowerCase()?0:1);
    } else {
      var as=senRank.findIndex(function(s){return(a.title||'').includes(s);});
      var bs=senRank.findIndex(function(s){return(b.title||'').includes(s);});
      return (as<0?99:as)-(bs<0?99:bs);
    }
  });
  if (!eligible.length) return null;
  usedIv[s][eligible[0].id]=true;
  return eligible[0];
}
function findRoom(s,allRooms) {
  if (!usedRoom[s]) usedRoom[s]={};
  for (var i=0;i<allRooms.length;i++) { var rid=allRooms[i].id||allRooms[i].name||allRooms[i]; if (!usedRoom[s][rid]){usedRoom[s][rid]=true;return allRooms[i];} }
  return null;
}
var schedule=[], warnings=[];
candidates.forEach(function(candidate,ci){
  ROUNDS.forEach(function(round,ri){
    var s=round.startTime; var e=addMins(s,DURATION);
    if (conflictsWithBlocks(s,e,candidate.hardBlocks)) { warnings.push('EC-BLOCK: '+candidate.name+' hard block during '+round.name+' ('+s+'). Skipped.'); return; }
    if (exceedsHardStop(e,candidate.hardStop)) { warnings.push('EC-HARDSTOP: '+candidate.name+' hard stop '+candidate.hardStop+' — '+round.name+' ends '+e+'. Skipped.'); return; }
    var iv=findIv(candidate,round,interviewers);
    if (!iv) { warnings.push('EC-NO-IV: No interviewer for '+candidate.name+' in '+round.name+' at '+s+'.'); return; }
    var room=findRoom(s,rooms);
    if (!room) { warnings.push('EC-NO-ROOM: No room for '+candidate.name+' in '+round.name+' at '+s+'.'); return; }
    var backToBackNote=null;
    if ((candidate.preferences||[]).includes('back-to-back')) {
      var prev=schedule.filter(function(sl){return sl.candidateId===candidate.id;}).slice(-1)[0];
      if (prev&&toMins(s)-toMins(prev.endTime)>20) { backToBackNote='NOTE: '+candidate.name+' prefers back-to-back. Gap is '+(toMins(s)-toMins(prev.endTime))+' min.'; warnings.push(backToBackNote); }
    }
    var matchReason=round.name==='Technical/Domain'?'Matched on '+(iv.department||'domain')+' expertise':round.name==='Cross-Functional'?'Cross-functional pairing':'Senior evaluator for culture fit';
    schedule.push({ slotId:'SLOT-C'+(ci+1)+'-R'+(ri+1), candidateId:candidate.id||'C'+(ci+1), candidateName:candidate.name||'Candidate '+(ci+1), role:candidate.role||'Unknown', round:ri+1, roundName:round.name, interviewerId:iv.id, interviewerName:iv.name, interviewerDept:iv.department||'', interviewerTitle:iv.title||'', matchReason:matchReason, room:room.name||room.id||room, date:superDayDate, startTime:s, endTime:e, durationMinutes:DURATION, status:'scheduled' });
  });
});
return [{ json: { schedule:schedule, totalSlots:schedule.length, warnings:warnings, generatedAt:new Date().toISOString() } }];

var data=$input.first().json; var schedule=data.schedule||[]; var errors=[]; var warnings=(data.warnings||[]).slice();
if (schedule.length===0) errors.push('CRITICAL: Schedule is empty.');
var ivMap={}; schedule.forEach(function(s){ var k=s.interviewerId+'_'+s.startTime; if(ivMap[k]) errors.push('DOUBLE-BOOKING: '+s.interviewerName+' at '+s.startTime); ivMap[k]=true; });
var rmMap={}; schedule.forEach(function(s){ var k=s.room+'_'+s.startTime; if(rmMap[k]) errors.push('ROOM-CONFLICT: '+s.room+' at '+s.startTime); rmMap[k]=true; });
var cRounds={}; schedule.forEach(function(s){ if(!cRounds[s.candidateId]) cRounds[s.candidateId]=[]; cRounds[s.candidateId].push(s.round); });
Object.keys(cRounds).forEach(function(cId){ if(cRounds[cId].length<3){ var n=(schedule.find(function(s){return s.candidateId===cId;})||{}).candidateName||cId; warnings.push('PARTIAL: '+n+' has '+cRounds[cId].length+'/3 rounds (constraint-driven).'); } });
schedule.forEach(function(s){ if(!s.interviewerName) errors.push('NO-IV: Slot '+s.slotId+' missing interviewer.'); if(!s.room) errors.push('NO-ROOM: Slot '+s.slotId+' missing room.'); });
return [{ json: { schedule:data.schedule, totalSlots:data.totalSlots, generatedAt:data.generatedAt, isValid:errors.length===0, validationErrors:errors, validationWarnings:warnings, validatedAt:new Date().toISOString() } }];

var data=$input.first().json; var schedule=data.schedule||[]; var notifMap={};
schedule.forEach(function(slot){
  if (!notifMap[slot.candidateId]) notifMap[slot.candidateId]={ recipientType:'candidate', recipientId:slot.candidateId, name:slot.candidateName, role:slot.role, subject:'Your Super Day Schedule — '+slot.date, message:'Hi '+slot.candidateName+', your interview schedule for Super Day '+slot.date+' is confirmed.', slots:[] };
  notifMap[slot.candidateId].slots.push({ round:slot.roundName, time:slot.startTime+' – '+slot.endTime, room:slot.room, interviewer:slot.interviewerName, matchReason:slot.matchReason });
  var ivKey='IV_'+slot.interviewerId;
  if (!notifMap[ivKey]) notifMap[ivKey]={ recipientType:'interviewer', recipientId:slot.interviewerId, name:slot.interviewerName, department:slot.interviewerDept, title:slot.interviewerTitle, subject:'Panel Assignments — Super Day '+slot.date, message:'Hi '+slot.interviewerName+', you have panel assignments for Super Day '+slot.date+'.', slots:[] };
  notifMap[ivKey].slots.push({ candidate:slot.candidateName, role:slot.role, round:slot.roundName, time:slot.startTime+' – '+slot.endTime, room:slot.room });
});
var notifications=Object.values(notifMap);
var cSet={}; var ivSet={}; var rSet={};
schedule.forEach(function(s){ cSet[s.candidateId]=true; ivSet[s.interviewerId]=true; rSet[s.room]=true; });
var aditiSummary={ recipientType:'hr_lead', name:'Aditi', subject:'Super Day Schedule Ready — Review & Approve', message:'Your Super Day schedule has been generated. Please review and approve.', totalCandidates:Object.keys(cSet).length, totalInterviewers:Object.keys(ivSet).length, totalRooms:Object.keys(rSet).length, totalSlots:schedule.length, warnings:data.validationWarnings||[], approvalRequired:true };
return [{ json: { schedule:data.schedule, totalSlots:data.totalSlots, notifications:notifications, totalNotifications:notifications.length, aditiSummary:aditiSummary, generatedAt:data.generatedAt, validatedAt:data.validatedAt } }];

var body=$json.body||{};
var VALID=['interviewer_cancelled','candidate_late','candidate_noshow','room_unavailable'];
var PRIORITY={interviewer_cancelled:1,room_unavailable:2,candidate_late:3,candidate_noshow:4};
var dtype=body.disruptionType||'';
var affId=body.affectedId||null;
var affName=body.affectedName||'Unknown';
var curSched=body.currentSchedule||[];
var reportedAt=body.reportedAt||new Date().toISOString();
var notes=body.notes||'';
var lateMins=body.lateByMinutes||0;
if (!VALID.includes(dtype)) return [{ json:{ valid:false, error:'Invalid disruption type: '+dtype+'. Valid: '+VALID.join(', '), disruptionType:dtype } }];
if (!affId) return [{ json:{ valid:false, error:'affectedId is required', disruptionType:dtype } }];
if (curSched.length===0) return [{ json:{ valid:false, error:'currentSchedule is empty — cannot replan', disruptionType:dtype } }];
return [{ json:{ valid:true, disruptionType:dtype, disruptionPriority:PRIORITY[dtype], affectedId:affId, affectedName:affName, lateByMinutes:lateMins, notes:notes, reportedAt:reportedAt, currentSchedule:curSched } }];

var d=$json;
var schedule=(d.currentSchedule||[]).map(function(s){return Object.assign({},s);});
var cancelledId=d.affectedId; var cancelledName=d.affectedName;
var BACKUPS=[
  {id:'I8', name:'Ananya Iyer',   title:'Engineering Manager', department:'Backend Engineer',availableFrom:'10:00',availableTill:'17:00'},
  {id:'I10',name:'Amit Saharan',  title:'Backend Architect',   department:'Backend Engineer',availableFrom:'14:00',availableTill:'17:00'},
  {id:'I9', name:'Suresh Babu',   title:'Product Director',    department:'Product Designer',availableFrom:'10:00',availableTill:'17:00'},
  {id:'I11',name:'Lakshmi Reddy', title:'HR Business Partner', department:'Human Resources', availableFrom:'10:00',availableTill:'17:00'},
  {id:'I12',name:'Vikram Nambiar',title:'Chief of Staff',      department:'Leadership',      availableFrom:'10:00',availableTill:'17:00'}
];
function toMins(t){var p=t.split(':').map(Number);return p[0]*60+p[1];}
function addMins(t,m){var tot=toMins(t)+m;return String(Math.floor(tot/60)).padStart(2,'0')+':'+String(tot%60).padStart(2,'0');}
var senRank=['VP','Chief','Director','Lead','Senior','Manager','Architect','Partner'];
function senScore(t){for(var i=0;i<senRank.length;i++){if((t||'').includes(senRank[i]))return i;}return 99;}
var used={}; schedule.forEach(function(s){if(!used[s.startTime])used[s.startTime]={};used[s.startTime][s.interviewerId]=true;});
var affected=schedule.filter(function(s){return s.interviewerId===cancelledId||s.interviewerName===cancelledName;});
var swaps=[],escalations=[],senWarn=[];
affected.forEach(function(slot){
  var st=slot.startTime; var et=addMins(st,slot.durationMinutes||45);
  if(!used[st])used[st]={};
  var cands=BACKUPS.filter(function(iv){
    if(iv.id===cancelledId) return false;
    if(used[st]&&used[st][iv.id]) return false;
    if(toMins(st)<toMins(iv.availableFrom)) return false;
    if(toMins(et)>toMins(iv.availableTill)) return false;
    return true;
  }).sort(function(a,b){
    var dm=function(iv){return(iv.department||'').toLowerCase()===(slot.interviewerDept||'').toLowerCase()?0:1;};
    return dm(a)-dm(b)||senScore(a.title)-senScore(b.title);
  });
  if (!cands.length){escalations.push({slotId:slot.slotId,candidateName:slot.candidateName,round:slot.roundName,time:st+' – '+et,reason:'No backup available',action:'ESCALATE_TO_ADITI'});slot.status='unresolved';slot.escalated=true;return;}
  var bk=cands[0]; used[st][bk.id]=true;
  var lower=senScore(bk.title)>senScore(slot.interviewerTitle);
  if(lower) senWarn.push('SENIORITY-WARN: '+bk.name+' ('+bk.title+') replacing '+cancelledName+' ('+slot.interviewerTitle+') for '+slot.candidateName+' '+slot.roundName+'. Aditi approval needed.');
  slot.interviewerId=bk.id; slot.interviewerName=bk.name; slot.interviewerDept=bk.department; slot.interviewerTitle=bk.title;
  slot.matchReason='Backup for cancelled '+cancelledName; slot.seniorityFlag=lower?'Lower seniority — approval needed':null; slot.status='rescheduled';
  swaps.push({slotId:slot.slotId,candidateName:slot.candidateName,round:slot.roundName,time:st+' – '+et,originalIv:cancelledName,newIv:bk.name,newIvTitle:bk.title,seniorityLower:lower,room:slot.room});
});
return [{ json:{ updatedSchedule:schedule, disruptionType:'interviewer_cancelled', cancelledInterviewer:cancelledName, affectedSlotsCount:affected.length, swapsExecuted:swaps, escalations:escalations, seniorityWarnings:senWarn, requiresAditiApproval:senWarn.length>0||escalations.length>0, resolvedAt:new Date().toISOString() } }];

var d=$json;
var schedule=(d.currentSchedule||[]).map(function(s){return Object.assign({},s);});
var candId=d.affectedId; var candName=d.affectedName; var lateMins=d.lateByMinutes||30;
function toMins(t){var p=t.split(':').map(Number);return p[0]*60+p[1];}
function fromMins(m){return String(Math.floor(m/60)).padStart(2,'0')+':'+String(m%60).padStart(2,'0');}
function addMins(t,m){return fromMins(toMins(t)+m);}
var RDUR=45; var MINGAP=10;
var cSlots=schedule.filter(function(s){return s.candidateId===candId||s.candidateName===candName;}).sort(function(a,b){return toMins(a.startTime)-toMins(b.startTime);});
if(!cSlots.length) return [{ json:{ error:'Candidate '+candName+' not in schedule', disruptionType:'candidate_late' } }];
var hardStop=cSlots[0].hardStop||null;
var cursor=toMins(cSlots[0].startTime)+lateMins;
var newTimes=cSlots.map(function(){
  var t={start:cursor,end:cursor+RDUR}; cursor=cursor+RDUR+MINGAP; return t;
});
var canFit=!hardStop||newTimes[newTimes.length-1].end<=toMins(hardStop);
var warns=[];
if(canFit){
  cSlots.forEach(function(slot,i){
    var g=schedule.find(function(s){return s.slotId===slot.slotId;});
    if(g){g.startTime=fromMins(newTimes[i].start);g.endTime=fromMins(newTimes[i].end);g.status='rescheduled';g.lateNote='Shifted '+lateMins+' min. Gap compressed to '+MINGAP+' min.';}
  });
  warns.push(candName+' arrived '+lateMins+' min late. All '+cSlots.length+' rounds preserved with compressed gaps.');
} else {
  var done=0;
  cSlots.forEach(function(slot,i){
    var g=schedule.find(function(s){return s.slotId===slot.slotId;});
    if(g&&(!hardStop||newTimes[i].end<=toMins(hardStop))){g.startTime=fromMins(newTimes[i].start);g.endTime=fromMins(newTimes[i].end);g.status='rescheduled';done++;}
    else if(g){g.status='dropped_hardstop';g.dropNote='Exceeds hard stop '+hardStop;}
  });
  warns.push('ALERT: '+candName+' can only complete '+done+'/'+cSlots.length+' rounds before hard stop '+hardStop+'. Aditi alerted.');
}
return [{ json:{ updatedSchedule:schedule, disruptionType:'candidate_late', candidateName:candName, lateByMinutes:lateMins, allRoundsFit:canFit, gapCompressedTo:MINGAP, warnings:warns, requiresAditiApproval:!canFit, resolvedAt:new Date().toISOString() } }];

var d=$json;
var schedule=(d.currentSchedule||[]).map(function(s){return Object.assign({},s);});
var candId=d.affectedId; var candName=d.affectedName;
var affected=[]; var freedIv=[];
schedule.forEach(function(slot){
  if(slot.candidateId===candId||slot.candidateName===candName){
    slot.status='vacant_no_show'; slot.dropNote=candName+' did not show. Slot freed.';
    affected.push(slot);
    if(!freedIv.find(function(iv){return iv.id===slot.interviewerId;})){
      freedIv.push({id:slot.interviewerId,name:slot.interviewerName,slots:[slot.startTime+' – '+slot.endTime+' ('+slot.roundName+')']});
    } else {
      freedIv.find(function(iv){return iv.id===slot.interviewerId;}).slots.push(slot.startTime+' – '+slot.endTime+' ('+slot.roundName+')');
    }
  }
});
return [{ json:{ updatedSchedule:schedule, disruptionType:'candidate_noshow', candidateName:candName, affectedSlotsCount:affected.length, freedInterviewers:freedIv, aditiAlert:'Candidate '+candName+' did not show. '+affected.length+' slots vacant. '+freedIv.length+' interviewers freed.', requiresAditiApproval:true, resolvedAt:new Date().toISOString() } }];

var d=$json;
var schedule=(d.currentSchedule||[]).map(function(s){return Object.assign({},s);});
var roomName=d.affectedName||d.affectedId;
function toMins(t){var p=t.split(':').map(Number);return p[0]*60+p[1];}
function fromMins(m){return String(Math.floor(m/60)).padStart(2,'0')+':'+String(m%60).padStart(2,'0');}
function addMins(t,m){return fromMins(toMins(t)+m);}
var allRooms=[]; schedule.forEach(function(s){if(!allRooms.includes(s.room))allRooms.push(s.room);});
var roomUsage={}; schedule.forEach(function(s){if(!roomUsage[s.startTime])roomUsage[s.startTime]={};roomUsage[s.startTime][s.room]=s.slotId;});
var affected=schedule.filter(function(s){return s.room===roomName;});
var swaps=[],staggered=[],escalations=[];
affected.forEach(function(slot){
  var st=slot.startTime;
  var freeRoom=allRooms.find(function(r){return r!==roomName&&(!roomUsage[st]||!roomUsage[st][r]);});
  if(freeRoom){
    if(!roomUsage[st])roomUsage[st]={};
    roomUsage[st][freeRoom]=slot.slotId;
    slot.room=freeRoom; slot.status='room_moved'; slot.roomNote='Moved from '+roomName+' to '+freeRoom+' (same time).';
    swaps.push({slotId:slot.slotId,candidateName:slot.candidateName,from:roomName,to:freeRoom,time:st});
  } else {
    var newSt=addMins(st,15); var newEt=addMins(slot.endTime,15);
    var hardOk=!slot.hardStop||toMins(newEt)<=toMins(slot.hardStop);
    var freeRoomStag=allRooms.find(function(r){return r!==roomName&&(!roomUsage[newSt]||!roomUsage[newSt][r]);});
    if(!hardOk||!freeRoomStag){
      escalations.push({slotId:slot.slotId,candidateName:slot.candidateName,round:slot.roundName,time:st,reason:!hardOk?'Stagger exceeds hard stop':'No room after stagger',action:'ESCALATE_TO_ADITI'});
      slot.status='unresolved'; slot.escalated=true;
    } else {
      if(!roomUsage[newSt])roomUsage[newSt]={};
      roomUsage[newSt][freeRoomStag]=slot.slotId;
      slot.startTime=newSt; slot.endTime=newEt; slot.room=freeRoomStag; slot.status='room_staggered';
      slot.roomNote='Staggered 15 min to '+newSt+' in '+freeRoomStag+' ('+roomName+' unavailable).';
      staggered.push({slotId:slot.slotId,candidateName:slot.candidateName,from:roomName,to:freeRoomStag,newTime:newSt});
    }
  }
});
return [{ json:{ updatedSchedule:schedule, disruptionType:'room_unavailable', unavailableRoom:roomName, affectedSlotsCount:affected.length, roomSwaps:swaps, staggeredSlots:staggered, escalations:escalations, requiresAditiApproval:escalations.length>0, resolvedAt:new Date().toISOString() } }];

var d=$json;
var summary=[];
if(d.disruptionType==='interviewer_cancelled'){
  summary.push('Interviewer '+d.cancelledInterviewer+' cancelled.');
  summary.push((d.swapsExecuted||[]).length+' slot(s) reassigned to backup.');
  if((d.escalations||[]).length>0) summary.push(d.escalations.length+' slot(s) could not be resolved — manual intervention needed.');
  if((d.seniorityWarnings||[]).length>0) summary.push('Seniority mismatch — Aditi approval required.');
} else if(d.disruptionType==='candidate_late'){
  summary.push('Candidate '+d.candidateName+' is '+d.lateByMinutes+' min late.');
  summary.push(d.allRoundsFit?'All rounds rescheduled with '+d.gapCompressedTo+' min gaps.':'Cannot fit all rounds — Aditi alerted.');
} else if(d.disruptionType==='candidate_noshow'){
  summary.push('Candidate '+d.candidateName+' no-show.');
  summary.push(d.affectedSlotsCount+' slot(s) vacant. '+(d.freedInterviewers||[]).length+' interviewer(s) freed.');
} else if(d.disruptionType==='room_unavailable'){
  summary.push('Room '+d.unavailableRoom+' unavailable.');
  summary.push((d.roomSwaps||[]).length+' slot(s) moved to alternate rooms.');
  summary.push((d.staggeredSlots||[]).length+' slot(s) staggered by 15 min.');
  if((d.escalations||[]).length>0) summary.push(d.escalations.length+' slot(s) escalated.');
}
return [{ json:{ updatedSchedule:d.updatedSchedule, disruptionType:d.disruptionType, summary:summary, requiresAditiApproval:d.requiresAditiApproval||false, escalations:d.escalations||[], seniorityWarnings:d.seniorityWarnings||[], warnings:d.warnings||[], resolvedAt:d.resolvedAt||new Date().toISOString() } }];
